// ===== 1. OBTENER DATA DEL WEBHOOK =====
const webhookData = $('Webhook Evolution API').first().json;

// Soporte para distintas estructuras posibles
const data = webhookData?.body?.data || webhookData?.data || webhookData;

// ===== 2. DATOS BÁSICOS =====
const messageType = data?.messageType || 'unknown';

let userMessage = '';
let phoneNumber = data?.key?.remoteJid?.replace('@s.whatsapp.net', '') 
  || data?.sender 
  || data?.from 
  || `user_${Date.now()}`;
let pushName = data?.pushName || 'Cliente';

// ===== 3. PROCESAR MENSAJE =====
if (messageType === 'conversation') {
  userMessage = data?.message?.conversation || '';
} 
else if (messageType === 'extendedTextMessage') {
  userMessage = data?.message?.extendedTextMessage?.text || '';
} 
else if (messageType === 'audioMessage') {
  try {
    const transcription = $('Transcribir con Whisper').first();
    userMessage = transcription?.json?.text || '[Audio no transcrito]';
  } catch (e) {
    userMessage = '[Error al transcribir audio]';
  }
} 
else {
  userMessage = '[Tipo de mensaje no soportado]';
}

// ===== 4. SUPABASE CONFIG =====
const SUPABASE_URL = 'https://lquapfdlkztqfihjvuxv.supabase.co';
const SUPABASE_KEY = 'TU_KEY_AQUI'; // ⚠️ recomendable mover a credenciales

const headers = {
  apikey: SUPABASE_KEY,
  Authorization: `Bearer ${SUPABASE_KEY}`,
  'Content-Type': 'application/json'
};

// ===== 5. TRAER PRECIOS =====
let prices = {};

try {
  const response = await fetch(
    `${SUPABASE_URL}/rest/v1/products?available=eq.true&category=eq.precio`,
    {
      method: 'GET',
      headers
    }
  );

  const pricesResult = await response.json();

  if (Array.isArray(pricesResult)) {
    pricesResult.forEach(p => {
      if (p.name && p.price) {
        prices[p.name] = p.price;
      }
    });
  }

} catch (error) {
  console.log('Error trayendo precios:', error);
}

// ===== 6. SABORES DISPONIBLES =====
let flavors = '';

try {
  flavors = $('get_flavors')
    .all()
    .map(i => i.json.name)
    .join(', ');
} catch (e) {
  flavors = '';
}

// ===== 7. OUTPUT FINAL =====
return [
  {
    json: {
      chatInput: userMessage,
      sessionId: phoneNumber,
      sessionKey: phoneNumber,
      phoneNumber: phoneNumber,
      pushName: pushName,
      instanceName: webhookData?.body?.instance || webhookData?.instance || '',
      messageType: messageType,
      timestamp: new Date().toISOString(),
      flavors_available: flavors,
      prices: prices
    }
  }
];

const action = query.action;
const customer_name = query.customer_name;
const delivery_type = query.delivery_type;
const delivery_address = query.delivery_address;
const delivery_time = query.delivery_time;
const total = query.total;
const notes = query.notes;
const order_id = query.order_id;

const SUPABASE_URL = 'https://lquapfdlkztqfihjvuxv.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImxxdWFwZmRsa3p0cWZpaGp2dXh2Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MzU4MzExOSwiZXhwIjoyMDg5MTU5MTE5fQ.E9QW8V2kV55pmgI8Tn7dqkvlo6l80eew6DgGHYzDtvE';

const headers = {
  'apikey': SUPABASE_KEY,
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

try {
  if (action === 'save') {
    const saveResult = await this.helpers.httpRequest({
      method: 'POST',
      url: `${SUPABASE_URL}/rest/v1/orders`,
      headers,
      body: JSON.stringify({
        customer_name: customer_name,
        delivery_type: delivery_type,
        delivery_address: delivery_address || null,
        delivery_time: delivery_time,
        total: total,
        notes: notes,
        status: 'pending'
      })
    });

    const order = Array.isArray(saveResult) ? saveResult[0] : saveResult;
    const newOrderId = order.id;

    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${SUPABASE_URL}/rest/v1/orders?id=eq.${newOrderId}`,
      headers,
      body: JSON.stringify({ status: 'confirmed' })
    });

    return `Pedido guardado y confirmado. ID: ${newOrderId}`;

  } else if (action === 'cancel') {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${SUPABASE_URL}/rest/v1/orders?id=eq.${order_id}`,
      headers,
      body: JSON.stringify({ status: 'cancelled' })
    });
    return 'Pedido cancelado exitosamente.';
  }

  return `action no reconocida: ${action}`;

} catch(e) {
  return `ERROR: ${e.message}`;
}

