const qty = query.quantity;

const SUPABASE_URL = 'https://lquapfdlkztqfihjvuxv.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImxxdWFwZmRsa3p0cWZpaGp2dXh2Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MzU4MzExOSwiZXhwIjoyMDg5MTU5MTE5fQ.E9QW8V2kV55pmgI8Tn7dqkvlo6l80eew6DgGHYzDtvE';
const headers = {
  'apikey': SUPABASE_KEY,
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'Content-Type': 'application/json'
};

const result = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/products?available=eq.true&category=eq.precio`,
  headers
});

const prices = {};
result.forEach(p => { prices[p.name] = p.price; });

const pDocena = prices['Docena'] || 25000;
const pMediaDocena = prices['Media docena'] || 15000;
const pIndividual = prices['Empanada individual'] || 2500;

const docenas = Math.floor(qty / 12);
const resto = qty % 12;
const mediaDocenas = resto >= 6 ? 1 : 0;
const individuales = resto >= 6 ? resto - 6 : resto;

const total = (docenas * pDocena) + (mediaDocenas * pMediaDocena) + (individuales * pIndividual);

const desglose = [];
if (docenas > 0) desglose.push(`${docenas} docena${docenas > 1 ? 's' : ''}: $${(docenas * pDocena).toLocaleString('es-AR')}`);
if (mediaDocenas > 0) desglose.push(`1 media docena: $${pMediaDocena.toLocaleString('es-AR')}`);
if (individuales > 0) desglose.push(`${individuales} individual${individuales > 1 ? 'es' : ''}: $${(individuales * pIndividual).toLocaleString('es-AR')}`);

return `Total para ${qty} empanadas: $${total.toLocaleString('es-AR')} (${desglose.join(' + ')})`;
